{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/IndentationRuleRegressionTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.INDENT_SIZE_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

internal class IndentationRuleRegressionTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given an expression body with try-catch and catch on next line then do not emit indent violations`() {
        val code =
            """
            fun test() = try {
              1
            }
            catch(_: Throwable) {
              2
            }
            """.trimIndent()

        indentationRuleAssertThat(code)
            .withEditorConfigOverride(INDENT_SIZE_PROPERTY to 2)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a typealias with the referenced type on next line then do not emit indent violations`() {
        val code =
            """
            typealias Foo =
              HashMap<Bar, Baz?>
            """.trimIndent()

        indentationRuleAssertThat(code)
            .withEditorConfigOverride(INDENT_SIZE_PROPERTY to 2)
            .hasNoLintViolations()
    }
}
"}

